
"use client";

import React, { useRef, useEffect, useState } from 'react';
import { Ninja, Level } from '@/lib/game-data';

/**
 * @fileOverview Spelmotorn för Ninjago: Master Edition.
 * Hanterar rendering av sprites från Base64, parallax-bakgrunder och elementarkrafter.
 */

// KLISTRA IN DIN LÅNGA BASE64-STRÄNG HÄR MELLAN CITATTECKNEN!
const SPRITE_SHEET_URL = ''; 

interface GameEngineProps {
  ninja: Ninja;
  level: Level;
  onGameOver: (score: number) => void;
  onLevelComplete: (points: number) => void;
}

export function GameEngine({ ninja, level, onGameOver, onLevelComplete }: GameEngineProps) {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const [isMobile, setIsMobile] = useState(false);
  const [spinEnergy, setSpinEnergy] = useState(0);

  const keys = useRef<{ [key: string]: boolean }>({});
  const touchInput = useRef<{ left: boolean, right: boolean, jump: boolean, fire: boolean, spin: boolean }>({
    left: false, right: false, jump: false, fire: false, spin: false
  });

  const spriteSheet = useRef<HTMLImageElement | null>(null);
  const [imageLoaded, setImageLoaded] = useState(false);

  useEffect(() => {
    setIsMobile('ontouchstart' in window);
    
    const img = new Image();
    img.src = SPRITE_SHEET_URL;
    
    img.onload = () => {
      spriteSheet.current = img;
      setImageLoaded(true);
      console.log("SPRITE SUCCESS: Ninjago-bilden laddad via Base64!");
    };

    img.onerror = () => {
      console.error("SPRITE ERROR: Kunde inte ladda bilden! Se till att SPRITE_SHEET_URL innehåller en giltig Base64-sträng.");
    };

    const handleKeyDown = (e: KeyboardEvent) => keys.current[e.code] = true;
    const handleKeyUp = (e: KeyboardEvent) => keys.current[e.code] = false;
    window.addEventListener('keydown', handleKeyDown);
    window.addEventListener('keyup', handleKeyUp);
    return () => {
      window.removeEventListener('keydown', handleKeyDown);
      window.removeEventListener('keyup', handleKeyUp);
    };
  }, []);

  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    const gravity = 0.5;
    const friction = 0.85;
    const moveAccel = 1.1;
    const jumpForce = -13.5;

    let cameraX = 0;
    let screenShake = 0;
    let gameActive = true;
    let particles: any[] = [];
    let projectiles: any[] = [];
    let frameCount = 0;
    
    const player = {
      x: 100, y: 400, width: 85, height: 105, dx: 0, dy: 0,
      jumping: false, color: ninja.color, score: 0,
      fireCooldown: 0, facingRight: true, isSpinjitzu: false,
      spinTimer: 0, energy: 0, rotation: 0, frame: 0
    };

    const platforms = [
      { x: 0, y: 550, width: 10000, height: 100, color: '#3d2b1f' },
      { x: 400, y: 420, width: 300, height: 50, color: '#4a3728' },
      { x: 900, y: 320, width: 250, height: 50, color: '#4a3728' },
      { x: 1300, y: 450, width: 350, height: 50, color: '#4a3728' },
      { x: 1800, y: 350, width: 300, height: 50, color: '#4a3728' },
      { x: 2300, y: 430, width: 400, height: 50, color: '#4a3728' },
      { x: 3000, y: 300, width: 250, height: 50, color: '#4a3728' },
      { x: 3600, y: 450, width: 450, height: 50, color: '#4a3728' },
      { x: 4200, y: 350, width: 300, height: 50, color: '#4a3728' },
      { x: 5000, y: 400, width: 600, height: 50, color: '#4a3728' },
    ];

    const enemies: any[] = Array.from({ length: 45 }, (_, i) => ({
      x: 1500 + i * 480, y: 460, width: 75, height: 95, hp: 1, dx: -2.8,
      isFrozen: false, frozenTimer: 0, originalX: 1500 + i * 480, 
      spriteRow: 2, spriteCol: 0
    }));

    const boss = { 
      x: 9000, y: 350, width: 160, height: 200, 
      hp: level.boss.healthMultiplier * 15, maxHp: level.boss.healthMultiplier * 15, 
      active: false, spriteRow: level.boss.spriteRow, spriteCol: level.boss.spriteCol
    };

    function createParticle(x: number, y: number, color: string, speed = 8) {
      for (let i = 0; i < 8; i++) {
        particles.push({
          x, y,
          dx: (Math.random() - 0.5) * speed,
          dy: (Math.random() - 0.5) * speed,
          life: 30 + Math.random() * 20,
          color,
          size: Math.random() * 5 + 2
        });
      }
    }

    function drawSprite(row: number, col: number, p: any, x: number, y: number, flip = false) {
      if (!spriteSheet.current || !imageLoaded) return;

      ctx!.save();
      ctx!.translate(x + p.width / 2, y + p.height / 2);
      if (flip) ctx!.scale(-1, 1);

      const sw = spriteSheet.current.width / 6; 
      const sh = spriteSheet.current.height / 3; 
      const sx = col * sw;
      const sy = row * sh;

      ctx!.drawImage(
        spriteSheet.current,
        sx, sy, sw, sh,
        -p.width / 2, -p.height / 2, p.width, p.height
      );
      
      ctx!.restore();
    }

    function gameLoop() {
      if (!gameActive) return;
      frameCount++;

      ctx!.fillStyle = '#0a0a1a'; 
      ctx!.fillRect(0, 0, canvas!.width, canvas!.height);
      
      // PARALLAX
      ctx!.fillStyle = '#151525';
      for (let i = 0; i < 6; i++) {
        const bx = i * 1600 - (cameraX * 0.1) % 1600;
        ctx!.beginPath();
        ctx!.moveTo(bx, 600);
        ctx!.lineTo(bx + 800, 200);
        ctx!.lineTo(bx + 1600, 600);
        ctx!.fill();
      }

      if (screenShake > 0) {
        ctx!.save();
        ctx!.translate((Math.random() - 0.5) * screenShake, (Math.random() - 0.5) * screenShake);
        screenShake *= 0.85;
      }

      const moveLeft = keys.current['ArrowLeft'] || touchInput.current.left;
      const moveRight = keys.current['ArrowRight'] || touchInput.current.right;
      const jumpKey = keys.current['Space'] || touchInput.current.jump;
      const fireKey = keys.current['KeyX'] || touchInput.current.fire;
      const spinKey = keys.current['KeyZ'] || touchInput.current.spin;

      // PHYSICS
      if (moveLeft) { player.dx -= moveAccel; player.facingRight = false; }
      if (moveRight) { player.dx += moveAccel; player.facingRight = true; }
      player.dx *= friction;
      player.dy += gravity;
      player.x += player.dx;
      player.y += player.dy;

      platforms.forEach(p => {
        if (player.x < p.x + p.width && player.x + player.width > p.x &&
            player.y + player.height > p.y && player.y + player.height < p.y + p.height + player.dy) {
          player.y = p.y - player.height;
          player.dy = 0;
          player.jumping = false;
        }
      });

      if (jumpKey && !player.jumping) {
        player.dy = jumpForce;
        player.jumping = true;
      }

      cameraX = Math.max(0, Math.min(player.x - 350, 8500));

      // KRAFTER
      if (fireKey && player.fireCooldown <= 0 && !player.isSpinjitzu) {
        projectiles.push({
          x: player.facingRight ? player.x + player.width : player.x,
          y: player.y + player.height / 2,
          dx: player.facingRight ? 18 : -18,
          color: player.color,
          type: ninja.id,
          size: ninja.id === 'lloyd' ? 35 : 18
        });
        player.fireCooldown = 30;
      }
      if (player.fireCooldown > 0) player.fireCooldown--;

      if (spinKey && player.energy >= 100 && !player.isSpinjitzu) {
        player.isSpinjitzu = true;
        player.spinTimer = 180; 
        player.energy = 0;
        setSpinEnergy(0);
        screenShake = 25;
      }
      if (player.isSpinjitzu) {
        player.spinTimer--;
        player.rotation += 0.8;
        player.dx = player.facingRight ? 14 : -14;
        if (player.spinTimer <= 0) player.isSpinjitzu = false;
      }

      ctx!.save();
      ctx!.translate(-cameraX, 0);

      // PLATTFORMAR
      platforms.forEach(p => {
        ctx!.fillStyle = p.color;
        ctx!.fillRect(p.x, p.y, p.width, p.height);
        ctx!.strokeStyle = 'rgba(255,255,255,0.15)';
        ctx!.lineWidth = 2;
        ctx!.strokeRect(p.x, p.y, p.width, p.height);
      });

      // FIENDER
      enemies.forEach((e, i) => {
        if (!e.isFrozen) {
          e.x += e.dx;
          if (Math.abs(e.x - e.originalX) > 300) e.dx *= -1;
        } else {
          e.frozenTimer--;
          if (e.frozenTimer <= 0) e.isFrozen = false;
        }
        
        drawSprite(e.spriteRow, e.spriteCol, e, e.x, e.y, e.dx > 0);

        if (player.x < e.x + e.width && player.x + player.width > e.x &&
            player.y < e.y + e.height && player.y + player.height > e.y) {
          if (player.isSpinjitzu) { 
            enemies.splice(i, 1); 
            player.score += 250; 
            createParticle(e.x, e.y, '#fff', 12);
          } else if (!e.isFrozen) { 
            gameActive = false; 
            onGameOver(player.score); 
          }
        }
      });

      // SKOTT
      projectiles.forEach((p, i) => {
        p.x += p.dx;
        ctx!.save();
        ctx!.shadowBlur = 25;
        ctx!.shadowColor = p.color;
        ctx!.fillStyle = p.color;
        ctx!.beginPath(); ctx!.arc(p.x, p.y, p.size, 0, Math.PI * 2); ctx!.fill();
        ctx!.restore();
        
        enemies.forEach((e, ei) => {
          if (p.x > e.x && p.x < e.x + e.width && p.y > e.y && p.y < e.y + e.height) {
            if (p.type === 'zane') {
              e.isFrozen = true; e.frozenTimer = 120;
            } else {
              enemies.splice(ei, 1);
            }
            player.score += 250; 
            player.energy = Math.min(100, player.energy + 10); 
            setSpinEnergy(player.energy);
            projectiles.splice(i, 1);
          }
        });

        if (p.x > boss.x && p.x < boss.x + boss.width && p.y > boss.y && p.y < boss.y + boss.height) {
          boss.hp -= (p.type === 'lloyd' ? 2 : 1); 
          projectiles.splice(i, 1);
          if (boss.hp <= 0) { gameActive = false; onLevelComplete(player.score + 5000); }
        }
        if (Math.abs(p.x - player.x) > 1300) projectiles.splice(i, 1);
      });

      // PLAYER
      if (player.isSpinjitzu) {
        ctx!.save();
        ctx!.translate(player.x + player.width / 2, player.y + player.height / 2);
        ctx!.rotate(player.rotation);
        const grad = ctx!.createRadialGradient(0, 0, 0, 0, 0, 90);
        grad.addColorStop(0, player.color);
        grad.addColorStop(1, 'transparent');
        ctx!.fillStyle = grad;
        for (let i = 0; i < 5; i++) {
          ctx!.rotate(Math.PI * 0.4);
          ctx!.beginPath(); ctx!.ellipse(0, 0, 50, 110, 0, 0, Math.PI * 2); ctx!.fill();
        }
        ctx!.restore();
      } else {
        drawSprite(0, ninja.spriteCol, player, player.x, player.y, !player.facingRight);
      }

      // BOSS
      if (cameraX > 8000) {
        boss.active = true;
        drawSprite(boss.spriteRow, boss.spriteCol, boss, boss.x, boss.y, player.x > boss.x);
        
        ctx!.restore();
        ctx!.fillStyle = 'rgba(0,0,0,0.85)'; ctx!.fillRect(150, 50, 500, 30);
        ctx!.fillStyle = '#ff0044'; ctx!.fillRect(150, 50, (boss.hp / boss.maxHp) * 500, 30);
        ctx!.strokeStyle = '#fff'; ctx!.lineWidth = 3; ctx!.strokeRect(150, 50, 500, 30);
        ctx!.save(); ctx!.translate(-cameraX, 0);
      }

      particles.forEach((p, i) => {
        p.x += p.dx; p.y += p.dy; p.life--;
        ctx!.fillStyle = p.color;
        ctx!.globalAlpha = p.life / 50;
        ctx!.fillRect(p.x, p.y, p.size, p.size);
        if (p.life <= 0) particles.splice(i, 1);
      });
      ctx!.globalAlpha = 1;

      ctx!.restore();
      if (screenShake > 0) ctx!.restore();

      if (player.y > 800) { player.x = cameraX + 50; player.y = 100; player.dy = 0; }

      requestAnimationFrame(gameLoop);
    }

    gameLoop();
  }, [ninja, level, imageLoaded]);

  return (
    <div className="relative w-full h-full flex items-center justify-center bg-black overflow-hidden rounded-2xl border-4 border-primary shadow-2xl">
      <canvas ref={canvasRef} width={800} height={600} className="w-full h-auto max-w-4xl" />
      <div className="absolute top-4 right-8 flex flex-col items-end gap-2">
        <div className="w-48 h-8 bg-black/80 rounded-full border-2 border-white/20 p-1 backdrop-blur-sm overflow-hidden">
          <div className={`h-full bg-primary transition-all duration-300 rounded-full ${spinEnergy >= 100 ? 'animate-pulse bg-yellow-400' : ''}`} style={{ width: `${spinEnergy}%` }} />
        </div>
      </div>
      {isMobile && (
        <div className="absolute inset-0 pointer-events-none p-6">
          <div className="absolute bottom-10 left-10 flex gap-4 pointer-events-auto">
            <button onPointerDown={() => touchInput.current.left = true} onPointerUp={() => touchInput.current.left = false} className="w-16 h-16 bg-white/20 rounded-xl border-2 border-white/20 text-white text-2xl font-bold">←</button>
            <button onPointerDown={() => touchInput.current.right = true} onPointerUp={() => touchInput.current.right = false} className="w-16 h-16 bg-white/20 rounded-xl border-2 border-white/20 text-white text-2xl font-bold">→</button>
          </div>
          <div className="absolute bottom-10 right-10 flex flex-col items-end gap-4 pointer-events-auto">
            <button onPointerDown={() => touchInput.current.spin = true} onPointerUp={() => touchInput.current.spin = false} className={`w-20 h-20 rounded-full border-4 font-black text-xs ${spinEnergy >= 100 ? 'bg-yellow-500 animate-bounce' : 'bg-gray-500 opacity-50'}`}>SPIN!</button>
            <div className="flex gap-4">
              <button onPointerDown={() => touchInput.current.jump = true} onPointerUp={() => touchInput.current.jump = false} className="w-20 h-20 bg-primary/80 rounded-xl text-white font-black text-sm uppercase">HOPP</button>
              <button onPointerDown={() => touchInput.current.fire = true} onPointerUp={() => touchInput.current.fire = false} className="w-20 h-20 bg-accent/80 rounded-xl text-white font-black text-sm uppercase">KRAFT</button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}
